'use client';

import { useEffect } from 'react';
import Button from '@/components/ui/Button';

export default function ErrorBoundary({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  useEffect(() => {
    console.error(error);
  }, [error]);

  return (
    <div className="gc-container py-20 text-center">
      <div className="size-20 rounded-full bg-red-50 flex items-center justify-center mx-auto mb-6">
        <span className="text-3xl">😵</span>
      </div>
      <h2 className="gc-display text-2xl text-text mb-2">Something went wrong!</h2>
      <p className="text-sm text-muted font-medium mb-6 max-w-md mx-auto">
        We encountered an unexpected error. Please try again or go back to the home page.
      </p>
      <div className="flex gap-3 justify-center">
        <Button variant="primary" onClick={reset}>Try Again</Button>
        <Button variant="ghost" onClick={() => window.location.href = '/'}>Go Home</Button>
      </div>
    </div>
  );
}
